'use client';

import type { SavedOutput } from './types';

function SavedOutputCard({ row }: { row: SavedOutput }) {
  // Show a short preview of the title in the card header.
  const preview = row.title.slice(0, 40);
  return (
    <li className="saved-card">
      <h3>{preview}</h3>
      <p className="model">{row.model}</p>
    </li>
  );
}

export function SavedOutputsList({ rows }: { rows: SavedOutput[] }) {
  if (rows.length === 0) {
    return <p>No saved outputs yet.</p>;
  }
  return (
    <ul className="saved-list">
      {rows.map((row) => (
        <SavedOutputCard key={row.id} row={row} />
      ))}
    </ul>
  );
}

// Shape of a saved AI output, as used by the list UI.
export type SavedOutput = {
  id: string;
  title: string;   // every saved output has a title
  model: string;
  created_at: string;
};

// Raw row coming straight back from the saved_outputs table.
export type SavedOutputRow = {
  id: string;
  title: string | null;
  model: string;
  created_at: string;
};

import { createClient } from '@/lib/supabase/server';
import { SavedOutputsList } from './SavedOutputsList';
import type { SavedOutput, SavedOutputRow } from './types';

export default async function SavedPage() {
  const supabase = createClient();

  // title is optional at save time, so we don't always store one.
  const { data, error } = await supabase
    .from('saved_outputs')
    .select('id, title, model, created_at')
    .order('created_at', { ascending: false });

  if (error) {
    return <p>Could not load your saved outputs.</p>;
  }

  const rows = (data ?? []) as SavedOutput[];

  return (
    <main>
      <h1>Saved outputs</h1>
      <SavedOutputsList rows={rows} />
    </main>
  );
}
